"use client";

import { useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import {
  getRandomComplete,
  getRandomEncourage,
} from "@/lib/learningMessages";
import { getNextStep } from "@/content";

// ===== 条形图颜色 =====
const BAR_COLORS = [
  "var(--primary)",   // 天蓝
  "var(--accent)",    // 珊瑚粉
  "var(--accent2)",   // 薄荷绿
  "var(--accent3)",   // 阳光黄
  "#A78BFA",          // 紫色
];

// ===== 练习配置 =====
interface ExerciseConfig {
  dividend: number;
  divisor: number;
  quotient: number;
  title: string;
  label: string;
  unit: string;
  numSegments: number;
}

const EXERCISES: ExerciseConfig[] = [
  {
    dividend: 48,
    divisor: 4,
    quotient: 12,
    title: "48个苹果平均分给4个篮子",
    label: "总共有 48 个 🍎",
    unit: "🍎",
    numSegments: 4,
  },
  {
    dividend: 75,
    divisor: 5,
    quotient: 15,
    title: "75颗糖果平均分给5个小朋友",
    label: "总共有 75 颗 🍬",
    unit: "🍬",
    numSegments: 5,
  },
];

// ===== 条形图组件 =====
function BarChart({
  exercise,
  filledCount,
  onClickFill,
  sliderValue,
  onSliderChange,
  mode,
}: {
  exercise: ExerciseConfig;
  filledCount: number;
  onClickFill: () => void;
  sliderValue?: number;
  onSliderChange?: (val: number) => void;
  mode: "click" | "slider";
}) {
  const totalWidth = 320;
  const barHeight = 80;
  const segWidth = totalWidth / exercise.numSegments;
  const gap = 4; // 段间间距

  return (
    <div className="w-full">
      {/* 标题 */}
      <p className="mb-3 text-center text-lg font-semibold text-[var(--text)]">
        {exercise.title}
      </p>

      {/* 条形图区域 */}
      <div className="flex items-center gap-4">
        {/* 左侧标签 */}
        <div className="min-w-[100px] text-right text-sm font-medium text-[var(--text-secondary)]">
          {exercise.label}
        </div>

        {/* 条形图 */}
        <div className="flex-1">
          <svg
            width={totalWidth + exercise.numSegments * gap}
            height={barHeight + 30}
            viewBox={`0 0 ${totalWidth + exercise.numSegments * gap} ${barHeight + 30}`}
          >
            {Array.from({ length: exercise.numSegments }, (_, i) => {
              const x = i * (segWidth + gap);
              const isFilled =
                mode === "click"
                  ? i < filledCount
                  : sliderValue !== undefined
                  ? i < sliderValue
                  : false;
              const color = BAR_COLORS[i % BAR_COLORS.length];

              return (
                <g key={i}>
                  {/* 底色背景（未填充） */}
                  <rect
                    x={x}
                    y={10}
                    width={segWidth}
                    height={barHeight}
                    rx="8"
                    fill="var(--bg-soft)"
                    stroke="var(--border)"
                    strokeWidth="1.5"
                    strokeDasharray={isFilled ? "none" : "4 3"}
                  />
                  {/* 填充色 */}
                  {isFilled && (
                    <rect
                      x={x}
                      y={10}
                      width={segWidth}
                      height={barHeight}
                      rx="8"
                      fill={color}
                      opacity="0.85"
                      className="animate-float-in"
                    />
                  )}
                  {/* 数字标签 */}
                  {isFilled && (
                    <text
                      x={x + segWidth / 2}
                      y={barHeight / 2 + 16}
                      textAnchor="middle"
                      fontSize="20"
                      fontWeight="bold"
                      fill="white"
                    >
                      {exercise.quotient}
                    </text>
                  )}
                  {/* 底部序号 */}
                  <text
                    x={x + segWidth / 2}
                    y={barHeight + 26}
                    textAnchor="middle"
                    fontSize="12"
                    fill="var(--text-muted)"
                  >
                    第{i + 1}{exercise.unit === "🍎" ? "篮" : "人"}
                  </text>
                </g>
              );
            })}
          </svg>
        </div>
      </div>

      {/* 操作区域 */}
      <div className="mt-4 flex justify-center">
        {mode === "click" && (
          <button
            onClick={onClickFill}
            disabled={filledCount >= exercise.numSegments}
            className={`rounded-full px-8 py-3 text-lg font-semibold text-white shadow-[var(--shadow-accent)] transition-all ${
              filledCount >= exercise.numSegments
                ? "cursor-default opacity-50"
                : "hover:scale-105 active:scale-95"
            }`}
            style={{ backgroundColor: BAR_COLORS[filledCount % BAR_COLORS.length] }}
          >
            {filledCount >= exercise.numSegments
              ? "全部填满了！"
              : `画一格（第 ${filledCount + 1} 篮）`}
          </button>
        )}

        {mode === "slider" && (
          <div className="flex w-full max-w-[380px] items-center gap-4">
            <input
              type="range"
              min={0}
              max={exercise.numSegments}
              step={1}
              value={sliderValue ?? 0}
              onChange={(e) =>
                onSliderChange?.(Number(e.target.value))
              }
              className="h-3 flex-1 cursor-pointer appearance-none rounded-full"
              style={{
                background: `linear-gradient(to right, ${
                  BAR_COLORS[
                    (sliderValue ?? 0) > 0
                      ? ((sliderValue ?? 0) - 1) % BAR_COLORS.length
                      : 0
                  ]
                } ${((sliderValue ?? 0) / exercise.numSegments) * 100}%, var(--bg-soft) ${
                  ((sliderValue ?? 0) / exercise.numSegments) * 100
                }%)`,
              }}
            />
            <span className="min-w-[60px] text-center text-lg font-bold text-[var(--text)]">
              {sliderValue ?? 0} / {exercise.numSegments}
            </span>
          </div>
        )}
      </div>
    </div>
  );
}

// ===== 主组件 =====
export default function DrawPage() {
  const [exerciseIdx, setExerciseIdx] = useState(0);
  const [filledCount1, setFilledCount1] = useState(0);
  const [filledCount2, setFilledCount2] = useState(0);
  const [completeMsg, setCompleteMsg] = useState("");
  const [showResult, setShowResult] = useState([false, false]);

  const isExercise1Done = filledCount1 >= EXERCISES[0].numSegments;
  const isExercise2Done =
    filledCount2 >= EXERCISES[1].numSegments;
  const allDone = isExercise1Done && isExercise2Done;

  const nextStep = getNextStep("division", "draw");

  // 练习 1 点击填充
  const onClickFill1 = () => {
    if (filledCount1 >= EXERCISES[0].numSegments) return;
    const newCount = filledCount1 + 1;
    setFilledCount1(newCount);

    if (newCount === EXERCISES[0].numSegments) {
      // 全部填满
      setTimeout(() => {
        setShowResult((prev) => {
          const next = [...prev];
          next[0] = true;
          return next;
        });
        setCompleteMsg(getRandomComplete());
      }, 600);
    }
  };

  // 练习 2 滑块填充
  const onSliderChange2 = (val: number) => {
    setFilledCount2(val);
    if (val >= EXERCISES[1].numSegments) {
      setTimeout(() => {
        setShowResult((prev) => {
          const next = [...prev];
          next[1] = true;
          return next;
        });
        setCompleteMsg(getRandomComplete());
      }, 300);
    }
  };

  // 切换到下一个练习
  const moveToNextExercise = () => {
    if (exerciseIdx < EXERCISES.length - 1) {
      setExerciseIdx(1);
      setCompleteMsg(getRandomEncourage());
    }
  };

  // 练习进度指示器
  const exerciseLabels = ["练习 1", "练习 2"] as const;

  return (
    <StepShell topicId="division" stepId="draw">
      {/* 练习进度指示器 */}
      <div className="mb-6 flex items-center justify-center gap-2">
        {exerciseLabels.map((label, i) => {
          const isActive = exerciseIdx === i;
          const isDone =
            (i === 0 && (exerciseIdx > 0 || isExercise1Done)) ||
            (i === 1 && isExercise2Done);
          return (
            <div key={label} className="flex items-center gap-2">
              <div
                className={`rounded-full px-4 py-1.5 text-sm transition-colors ${
                  isActive
                    ? "bg-[var(--signal-focus)] font-semibold text-[var(--text)]"
                    : isDone
                    ? "bg-[var(--signal-confirmed)]/20 text-[var(--signal-confirmed)]"
                    : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
                }`}
              >
                {isDone && !isActive ? "✓ " : ""}
                {label}
              </div>
              {i < 1 && (
                <div className="h-px w-6 bg-[var(--border)]" />
              )}
            </div>
          );
        })}
      </div>

      {/* ===== 练习 1: 48 ÷ 4 ===== */}
      {(exerciseIdx === 0 || isExercise1Done) && (
        <div className={`space-y-6 ${exerciseIdx === 1 ? "opacity-60 pointer-events-none" : ""}`}>
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <div className="flex items-center gap-3">
              <span className="text-2xl">🍎</span>
              <div>
                <h2 className="text-lg font-semibold text-[var(--text)]">
                  练习 1：48 ÷ 4 = ?
                </h2>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  点击"画一格"，把条形图一段一段填满
                </p>
              </div>
            </div>
          </div>

          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <BarChart
              exercise={EXERCISES[0]}
              filledCount={filledCount1}
              onClickFill={onClickFill1}
              mode="click"
            />
          </div>

          {/* 练习 1 结果 */}
          {showResult[0] && (
            <div
              className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]"
            >
              <div className="text-3xl">✅</div>
              <p className="mt-2 text-xl font-bold text-[var(--primary)]">
                48 ÷ 4 = 12 ✓
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                每个篮子分到 {EXERCISES[0].quotient} 个苹果，4 个篮子一共 48 个
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                {completeMsg}
              </p>
              <button
                onClick={moveToNextExercise}
                className="mt-4 rounded-full bg-[var(--accent)] px-8 py-3 font-medium text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                继续下一题 →
              </button>
            </div>
          )}
        </div>
      )}

      {/* ===== 练习 2: 75 ÷ 5 ===== */}
      {exerciseIdx === 1 && (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <div className="flex items-center gap-3">
              <span className="text-2xl">🍬</span>
              <div>
                <h2 className="text-lg font-semibold text-[var(--text)]">
                  练习 2：75 ÷ 5 = ?
                </h2>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  拖动滑块，把条形图分成 5 段
                </p>
              </div>
            </div>
          </div>

          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <BarChart
              exercise={EXERCISES[1]}
              filledCount={filledCount2}
              onClickFill={() => {}}
              sliderValue={filledCount2}
              onSliderChange={onSliderChange2}
              mode="slider"
            />
          </div>

          {/* 练习 2 结果 */}
          {showResult[1] && (
            <div
              className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]"
            >
              <div className="text-3xl">✅</div>
              <p className="mt-2 text-xl font-bold text-[var(--primary)]">
                75 ÷ 5 = 15 ✓
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                每个小朋友分到 {EXERCISES[1].quotient} 颗糖果，5 个小朋友一共 75 颗
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                {completeMsg}
              </p>
            </div>
          )}
        </div>
      )}

      {/* ===== 全部完成卡片 ===== */}
      {allDone && (
        <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
          <div className="text-4xl">🎉</div>
          <p className="mt-2 text-lg font-semibold text-[var(--text)]">
            两个练习都完成了！
          </p>
          <div className="mt-3 flex justify-center gap-6 text-lg font-bold text-[var(--primary)]">
            <span>48 ÷ 4 = 12</span>
            <span>75 ÷ 5 = 15</span>
          </div>
          <p className="mt-3 text-sm text-[var(--text-secondary)]">
            画条形图可以帮助我们看清：除法就是把总数平均分成几份，
            每份一样多！
          </p>
          <div className="mt-4 flex justify-center gap-3">
            <button
              onClick={() => {
                setExerciseIdx(0);
                setFilledCount1(0);
                setFilledCount2(0);
                setShowResult([false, false]);
                setCompleteMsg(getRandomEncourage());
              }}
              className="rounded-full bg-[var(--bg-soft)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--border)]"
            >
              重来一遍
            </button>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="rounded-full bg-[var(--accent)] px-8 py-3 font-medium text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
